parameters.jsCode:
// ── Parser SRT ──────────────────────────────────────
const data = items[0].json.body || {};
const rawData = data.content || '';
const callbackUrl = data.callback_url || 'http://localhost:3001/update-scene';
const userAgentPrompt = data.user_agent_prompt || '';
const interval = parseFloat(data.sampling_sec) || 5;
const projectId = data.project_id || 'default_' + Date.now();

if (!rawData) return [{ json: { error: 'Contenuto SRT mancante' } }];

const timeMatches = rawData.match(/\d{2}:\d{2}:\d{2},\d{3}/g) || [];
if (!timeMatches.length) return [{ json: { error: 'Nessun timestamp trovato' } }];

const lastTs = timeMatches[timeMatches.length - 1];
const [h, m, sMs] = lastTs.split(':');
const [s, ms] = sMs.split(',');
const totalSeconds = parseInt(h) * 3600 + parseInt(m) * 60 + parseInt(s) + parseInt(ms) / 1000;
const numberOfFrames = Math.ceil(totalSeconds / interval);

return [{
  json: {
    project_id: projectId,
    user_agent_prompt: userAgentPrompt,
    sampling_sec: interval,
    raw_data: rawData,
    input_type: 'SRT',
    required_frames: numberOfFrames,
    total_duration_sec: totalSeconds.toFixed(2),
    callback_url: callbackUrl
  }
}];

// ── Parser PROMPTS (uno per riga) ────────────────────
const data = items[0].json.body || {};
const rawData = data.content || '';
const callbackUrl = data.callback_url || 'http://localhost:3001/update-scene';
const userAgentPrompt = data.user_agent_prompt || '';
const projectId = data.project_id || 'default_' + Date.now();

const prompts = rawData.split('\n').map(l => l.trim()).filter(Boolean);
const numberOfFrames = prompts.length;

// Formatta come JSON array per lo stesso AI Agent
const prebuiltScenes = JSON.stringify(prompts.map((p, i) => ({ scene_index: i, prompt: p })));

return [{
  json: {
    project_id: projectId,
    user_agent_prompt: userAgentPrompt,
    raw_data: rawData,
    input_type: 'PROMPTS',
    required_frames: numberOfFrames,
    prebuilt_scenes: prebuiltScenes,
    callback_url: callbackUrl
  }
}];

