parameters.jsCode:
// Estrai JSON dall'output AI Agent (per SRT) oppure usa prebuilt (per PROMPTS)
const item = items[0].json;

// Se è PROMPTS, usa le scene già costruite
if (item.prebuilt_scenes) {
  try {
    const scenes = JSON.parse(item.prebuilt_scenes);
    const result = scenes.map(s => ({
      json: {
        scene_index: s.scene_index,
        prompt: s.prompt,
        project_id: item.project_id,
        callback_url: item.callback_url,
        total_scenes: scenes.length
      }
    }));
    return result;
  } catch(e) {
    return [{ json: { error: 'Errore parsing PROMPTS: ' + e.message } }];
  }
}

// Altrimenti estrai dall'output dell'AI Agent (SRT)
const response = item.output || item.text || '';
const start = response.indexOf('[');
const end = response.lastIndexOf(']') + 1;
if (start === -1 || end === 0) {
  return [{ json: { error: 'JSON non trovato nell output AI', raw: response.slice(0, 200) } }];
}
try {
  const scenes = JSON.parse(response.substring(start, end));
  return scenes.map(s => ({
    json: {
      scene_index: s.scene_index !== undefined ? s.scene_index : 0,
      prompt: s.prompt || s.description || '',
      project_id: item.project_id,
      callback_url: item.callback_url,
      total_scenes: scenes.length
    }
  }));
} catch(e) {
  return [{ json: { error: 'Errore parsing JSON AI: ' + e.message } }];
}

